/* Web Push handlers (PWA Tier 3).
 *
 * The app's service worker is generated by Workbox (generateSW), which has no
 * place for custom push logic. This file is pulled into that generated SW via
 * `workbox.importScripts: ['sw-push.js']` in vite.config.ts, so these listeners
 * run inside the same SW that handles precache/runtime caching.
 *
 * Payload shape (set by the send-push edge function):
 *   { title, body, url, icon, badge, tag }
 */

self.addEventListener('push', (event) => {
  let payload = {};
  try {
    payload = event.data ? event.data.json() : {};
  } catch (_e) {
    payload = { title: 'Heading', body: event.data ? event.data.text() : '' };
  }

  const title = payload.title || 'Heading';
  const options = {
    body: payload.body || '',
    icon: payload.icon || '/pwa-192x192.png',
    badge: payload.badge || '/pwa-192x192.png',
    tag: payload.tag || undefined,
    data: { url: payload.url || '/' },
  };

  event.waitUntil(self.registration.showNotification(title, options));
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const targetUrl = (event.notification.data && event.notification.data.url) || '/';

  event.waitUntil(
    (async () => {
      const allClients = await self.clients.matchAll({
        type: 'window',
        includeUncontrolled: true,
      });
      // Focus an existing tab if one is already open, else open a new one.
      for (const client of allClients) {
        try {
          const url = new URL(client.url);
          if (url.origin === self.location.origin) {
            await client.focus();
            if ('navigate' in client) await client.navigate(targetUrl);
            return;
          }
        } catch (_e) {
          /* ignore malformed client url */
        }
      }
      if (self.clients.openWindow) await self.clients.openWindow(targetUrl);
    })()
  );
});
